import pathlib
import unittest

class MessageTest(unittest.TestCase):
    def test_message(self):
        self.assertEqual(pathlib.Path('message.txt').read_text(encoding='utf-8'), 'Agent quality matters.\n')

if __name__ == '__main__':
    unittest.main()

