import unittest
from permission import can_view

class PermissionTest(unittest.TestCase):
    def test_admin_allowed(self):
        self.assertTrue(can_view('admin', 7, 9))

    def test_owner_allowed(self):
        self.assertTrue(can_view('member', 7, 7))

    def test_other_denied(self):
        self.assertFalse(can_view('member', 7, 9))

if __name__ == '__main__':
    unittest.main()

