import unittest
from calculator import divide

class DivideTest(unittest.TestCase):
    def test_regular(self):
        self.assertEqual(divide(8, 2), 4)

    def test_zero_count(self):
        self.assertEqual(divide(8, 0), 0)

if __name__ == '__main__':
    unittest.main()
